const commits = $input.all()[0].json.body ? JSON.parse($input.all()[0].json.body) : ($input.all()[0].json || []);
const issues = $input.all()[1].json.body ? JSON.parse($input.all()[1].json.body) : ($input.all()[1].json || []);
const prs = $input.all()[2].json.body ? JSON.parse($input.all()[2].json.body) : ($input.all()[2].json || []);

const mergedPRs = Array.isArray(prs) ? prs.filter(p => p.merged_at !== null) : [];
const closedIssues = Array.isArray(issues) ? issues.filter(i => !i.pull_request) : [];

const formatCommit = c => ({
  hash: (c.sha || '').substring(0, 7),
  message: (c.commit?.message || '').split('\n')[0],
  author: c.commit?.author?.name || c.author?.login || 'unknown',
  date: c.commit?.author?.date || ''
});

const formatIssue = i => ({
  number: i.number,
  title: i.title,
  author: i.user?.login || 'unknown',
  closedAt: i.closed_at || ''
});

const formatPR = p => ({
  number: p.number,
  title: p.title,
  author: p.user?.login || 'unknown',
  mergedAt: p.merged_at || '',
  additions: p.additions || 0,
  deletions: p.deletions || 0
});

return {
  owner: $json.owner,
  repo: $json.repo,
  weekEnding: new Date().toISOString().split('T')[0],
  commits: (Array.isArray(commits) ? commits : []).map(formatCommit),
  closedIssues: closedIssues.map(formatIssue),
  mergedPRs: mergedPRs.map(formatPR),
  stats: {
    totalCommits: (Array.isArray(commits) ? commits : []).length,
    totalIssuesClosed: closedIssues.length,
    totalPRsMerged: mergedPRs.length
  }
};

