const response = $input.first().json;
let body = response.body;
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) {}
}

const content = body?.content?.[0]?.text || body?.content || JSON.stringify(body);

const report = `# 📬 Weekly Dev Summary

**Repository:** ${$json.owner}/${$json.repo}
**Week ending:** ${$json.weekEnding}

## 📊 Stats
- Commits: ${$json.stats.totalCommits}
- Issues closed: ${$json.stats.totalIssuesClosed}
- PRs merged: ${$json.stats.totalPRsMerged}

## 📝 Generated Summary
${content}

---
*Generated by n8n + Claude API*`;

return { summary: report };

